var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 저 많은 사람들 앞에서 자기 소개라니 상상만 해도 끔찍하군.","JPN":"ハハ、あの大勢の前で自己紹介するなんて、想像しただけでゾッとするな。","ENG":"Haha, just nerve-racking to even imagine having to introduce myself in front of all those people.","TWN":"哈哈，竟然要在這麼多人面前自我介紹，光想就覺得可怕呢。"},"stage":{"bg":"MS_1102","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"나처럼 외출하기 싫어하는 사람에겐 고역스러운 자리겠어.","JPN":"私のような外嫌いにはきつい状況だ。","ENG":"For someone who dislikes going outside like me, it seems awfully painful.","TWN":"對於像我這種不喜歡外出的人來說，應該是很痛苦的場合。"},"stage":{"bg":"MS_1102","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"하긴, 부담스러운 건 자네겠지만.","JPN":"ま、気が重いのは君の方なんだが。","ENG":"But, yeah. It’s you who is burdened, not me.","TWN":"不過，有壓力的人是你。"},"stage":{"bg":"MS_1102","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 조금만 참게나, 친구.","JPN":"それでも少し辛抱してくれ。","ENG":"So, hang in there, friend.","TWN":"就再多忍耐一下吧，朋友。"},"stage":{"bg":"MS_1102","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"우리에게는 이 세계가 앞으로 누구와 싸워야 하는지.","JPN":"我々には、これからこの世界が戦わねばならない相手について。","ENG":"Because we have a responsibility to tell how this world has fared thus far,","TWN":"因為我們有義務告訴大家，這個世界之後會需要對抗誰，"},"stage":{"bg":"MS_1102","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"또 이 세계가 이제까지 어떻게 살아남았는지 알려 줘야 할 의무가 있으니까.","JPN":"それから、この世界が今までどうやって存続してきたのかについて、教える義務があるからな。","ENG":"as well as who it must fight next.","TWN":"以及這個世界是如何存活至今的。"},"stage":{"bg":"MS_1102","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"계산에 따르면 우리가 관리할 수 있는 한계는 여기까지라네.","JPN":"計算によると、我々が管理できるのはここまでだ。","ENG":"If my calculations are correct, this is the extent of our management.","TWN":"根據計算，我們能管理的權限僅止於此。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"결과적으로 잠들어 있던 신을 깨우는 데 성공한 셈이지.","JPN":"結果的には眠っていた神を目覚めさせることに成功したわけさ。","ENG":"After countless failed attempts and sacrifices we made.","TWN":"就結果而言，算是成功喚醒沉睡的神。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"수없이 많은 실패와, 수없이 많은 희생을 치른 끝에.","JPN":"数え切れないほど多くの失敗と犠牲の末に。","ENG":"We have finally succeeded in waking up the slumbering god.","TWN":"但這是經過無數的失敗和犧牲才帶來的結果。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"마침내 우리가 넘어서야 할 상대에게.","JPN":"やっと我々が乗り越えるべき相手に。","ENG":"And now facing the one whom we must overcome.","TWN":"我們終於抵達需要超越的對象"},"stage":{"bg":"MAINSTREAM_NEW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"탐미엘에게 다다른 걸세.","JPN":"タミエルにたどり着いたのだ。","ENG":"Tammiel.","TWN":"塔米爾的面前。"},"stage":{"bg":"MAINSTREAM_NEW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"최초의 세계 이후, 우리가 줄곧 이루고자 했던 계획대로.","JPN":"最初の世界の後、ずっと掲げてきた計画どおりにな。","ENG":"After the first world, we have achieved everything we planned.","TWN":"最初的世界之後，按著我們一直想達成的計畫。"},"stage":{"bg":"MAINSTREAM_NEW_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 말 그대로, 여기까지라네.","JPN":"だが言葉どおり、ここまでさ。","ENG":"But literally, this is all.","TWN":"不過就如同我前面說的，僅止於此。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"우리의 계획도. 우리가 쌓아 왔던 모든 것도.","JPN":"我々の計画も、築いてきたすべても。","ENG":"Because nothing can be assumed or addressed from this point forward.","TWN":"我們的計畫，和我們至今所累積的一切，"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"이 시점 이후로는 상정하지 않았고, 상정할 수도 없었으니까.","JPN":"この時点より先は想定していなかったし、想定もできなかったんだ。","ENG":"Our plan, everything we have built... Nothing.","TWN":"從此之後，沒有計畫，也無法計畫。"},"stage":{"bg":"MAINSTREAM_000005","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"현존하는 테라브레인을 모두 동원해서 그 이후의 미래를 몇 번이고 계산하려 했네만.","JPN":"現存するテラブレインを総動員し、何度もその先の未来を計算しようとしたのだが。","ENG":"I have tried to calculate the future using all the Terrabrains known to exist, but...","TWN":"雖然動員過目前所有的特拉大腦，計算過幾次那之後的未來，"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003021","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"결과는 늘 같았어. 완벽한 미지수였지.","JPN":"結果は常に同じだった。完璧な未知数だ。","ENG":"The results were always the same. A perfect unknown.","TWN":"但結果都是一樣的，是完美的未知數。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003021","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"탐미엘이 다시 나타난 시기를 전후로 변수가 폭증하더군.","JPN":"タミエルが再び現れた時期を前後に、変数が爆増したのさ。","ENG":"Variables have been increasing exponentially ever since Tammiel appeared.","TWN":"塔米爾再次出現的時間點前後變數暴增。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003021","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};